if(rlen < nbytes) {
  unsigned char readbuf[1024];
  size_t nread;

  DEBUGASSERT(nbytes - rlen < sizeof(readbuf));
  result = Curl_xfer_recv(data, (char *)readbuf, nbytes - rlen, &nread);
  if(result)
    return result;
  if(!nread) /* EOF */
     return CURLE_RECV_ERROR;
  if(curlx_dyn_addn(&mq->recvbuf, readbuf, nread))
    return CURLE_OUT_OF_MEMORY;
  rlen = curlx_dyn_len(&mq->recvbuf);
}

if(data->req.writebytecount)
    infof(data, "upload completely sent off: %" FMT_OFF_T " bytes",
          data->req.writebytecount);
  else if(!data->req.download_done) {
    DEBUGASSERT(Curl_bufq_is_empty(&data->req.sendbuf));
    infof(data, Curl_creader_total_length(data) ?
          "We are completely uploaded and fine" :
          "Request completely sent off");
  }

if(data->req.shutdown) {
  bool done;
  result = Curl_xfer_send_shutdown(data, &done);
  if(result && data->req.shutdown_err_ignore) {
    infof(data, "Shutdown send direction error: %d. Broken server? "
          "Proceeding as if everything is ok.", result);
    result = CURLE_OK;
    done = TRUE;
  }

  if(result)
    return result;
  if(!done)
    return CURLE_AGAIN;
}

